head.script:
scwin.initData = {
	"isValidate" : false,
	"isSaveProcess" : false,
	"acbMappingCdObj" : {
		"deptNm" : "cmmnCd"
	},
	"acbMappingNmObj" : {
		"basinNm" : "upperCmmnCdNm"
	},
	"acbMappingCdObjDiv" : {
		"iemDivCd" : "cmmnCd"
	},
	"acbMappingNmObjDiv" : {
	},
	"isEqpChanged" : false,
	"isExcclcChanged" : false,
	"oldEqpSttusWthtSuplyBeginDe" : "",
	"oldEqpSttusEqpNm" : "",
	// 설비현황
	"valInfoEqp" : [
		{id : "deptNm", minLength : 1, maxLength : 40, mandatory : true},
		{id : "iemDivCd", minLength : 1, maxByteLength : 100, mandatory : true},
		{id : "wthtSuplyBeginDe", minLength : 6, maxByteLength : 8, mandatory : true, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "eqpNm", maxByteLength : 100, mandatory : true},
		{id : "eqpCpcty", maxByteLength : 22, number : true},
		{id : "invtCst", maxByteLength : 13, number : true},
		{id : "wthtUsefulYycnt", maxByteLength : 22, number : true},
		{id : "rmCtnt", maxByteLength : 4000}
	],
	// 수익현황
	"valInfoExcclc" : [
		// 그리드 저장이 안 돼서 주석처리 함_240109
		//{id : "wthtSuplyBeginDe", maxByteLength : 8, mandatory : true, number : true, dateFunc : ecsLib.validatorYearMonthDate},
		//{id : "eqpNm", maxByteLength : 100, mandatory : true},
		{id : "registDe", maxByteLength : 8, mandatory : true, number : true},
		{id : "cntrctNm", maxLength : 1000, mandatory : true},
		{id : "cntrctCpcty", maxByteLength : 22, number : true},
		{id : "ctrpdStrtDe", maxByteLength : 8, number : true},
		{id : "ctrpdEndDe", maxByteLength : 8, number : true},
		{id : "splval", maxByteLength : 13, number : true},
		{id : "vat", maxByteLength : 13, number : true},
		{id : "excclcAmt", maxByteLength : 13, number : true},
		{id : "bsnsDivNm", maxByteLength : 100},
		{id : "mrktDivNm", maxByteLength : 40}
	]
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCL1200000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("strtDt" , utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -30 *12));
	dmaSearchParam.set("endDt" , utilLib.getCurrentDate("yyyyMM"));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("divCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var endDate = dmaSearchParam.get("endDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var iemDivNm = dmaSearchParam.get("divCd");

	if (String(strtDate).length != 6 || String(endDate).length != 6) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	} else if (utilLib.minusYears(strtDate, endDate) > 40 ? true : false) {
		// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
		alert(utilLib.getMessage("ECS.INFO.00012", "40년")[0]);
		return;
	} else if (parseInt(strtDate) > parseInt(endDate)) {
		// 시작년월이 종료년월일보다 클수 없습니다.
		alert(utilLib.getMessage("ECS.INFO.00014")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&iemDivNm=${iemDivNm}`;

	var option = {
		action : "cl/wthtexcclc/retrieve-wtht-eqp-sttus.do"
			+ queryString,
		method : "get",
		resData : dltWthtEqpSttusList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수열설비 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnWthtEqpTotalRow.setValue(dltWthtEqpSttusList.getRowCount());
	var mandatoryList = scwin.initData.valInfoEqp.filter(obj => obj.mandatory);
	for (var i = 0; i < dltWthtEqpSttusList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdWthtEqpSttusList.setCellReadOnly(i, obj.id, true);
		});
	}
	scwin.initData.isEqpChanged = false;
	grdWthtExcclcSttusList.setReadOnly(false);
	scwin.clearWthtEqpSttus(true);
	scwin.initData.isExcclcChanged = false;
	btnAddRow1.setStyle("display", "inline-block");
	btnDelRow1.setStyle("display", "inline-block");
	// 조회 후 자동 선택 기능
	if (scwin.initData.oldEqpSttusWthtSuplyBeginDe && scwin.initData.oldEqpSttusEqpNm) {
		var eqpSttusIdx = grdWthtEqpSttusList.getAllJSON().findIndex(obj =>
			obj.wthtSuplyBeginDe == scwin.initData.oldEqpSttusWthtSuplyBeginDe && obj.eqpNm == scwin.initData.oldEqpSttusEqpNm);
		scwin.initData.oldEqpSttusWthtSuplyBeginDe = "";
		scwin.initData.oldEqpSttusEqpNm = "";
		if (eqpSttusIdx >= 0) {
			grdWthtEqpSttusList.setFocusedCell(eqpSttusIdx, 0);
			scwin.grdWthtEqpSttusList_oncellclick(eqpSttusIdx, 0);
		}
	}
	scwin.initData.isValidate = false;
};

/**
 * 수열정산 데이터 초기화 및 버튼초기화
 * @param
 * @return
 */
scwin.clearWthtEqpSttus = function(isClear) {
	btnAddRow2.setStyle("display", "none");
	btnDelRow2.setStyle("display", "none");
	btnDownExcel2.setStyle("display", "none");
	btnUploadExcel2.setStyle("display", "none");
	if (isClear) {
		dltWthtExcclcSttusList.removeAll();
	}
};

/**
 * 수열설비 클릭시 수열정산 데이터 조회 이벤트
 * @param
 * @return
 */
scwin.grdWthtEqpSttusList_oncellclick = function(row, col) {
	var iemDivNm = grdWthtEqpSttusList.getCellData(row, "iemDivNm");

	if (grdWthtEqpSttusList.getFocusedRowStatus() == "R" && iemDivNm == "03") {
		var wthtSuplyBeginDe = grdWthtEqpSttusList.getCellData(row, "wthtSuplyBeginDe");
		var eqpNm = grdWthtEqpSttusList.getCellData(row, "eqpNm");
		var queryString = `?wthtSuplyBeginDe=${wthtSuplyBeginDe}`;
		queryString += `&eqpNm=${eqpNm}`;

		var option = {
			action : "cl/wthtexcclc/retrieve-wtht-excclc-sttus.do"
				+ queryString,
			method : "get",
			resData : dltWthtExcclcSttusList,
			success : "scwin.inqireExcclcCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);

		var deptNm = grdWthtEqpSttusList.getCellData(row, "deptNm");
		var eqpNm = grdWthtEqpSttusList.getCellData(row, "eqpNm");
		spnWthtExcclcDeptLabel.setLabel(deptNm + " " + eqpNm + " ");
	} else {
		scwin.clearWthtEqpSttus(true);
		scwin.initData.isExcclcChanged = false;
		btnAddRow1.setStyle("display", "inline-block");
		btnDelRow1.setStyle("display", "inline-block");
		spnWthtExcclcDeptLabel.setLabel("");
		spnWthtExcclcTotalRow.setLabel("0");
	}
};

/**
 * 수열정산 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireExcclcCallback = function() {
	spnWthtExcclcTotalRow.setValue(dltWthtExcclcSttusList.getRowCount());
	var mandatoryList = scwin.initData.valInfoExcclc.filter(obj => obj.mandatory);
	for (var i = 0; i < dltWthtExcclcSttusList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdWthtExcclcSttusList.setCellReadOnly(i, obj.id, true);
		});
	}

	scwin.initData.isExcclcChanged = false;
	btnAddRow1.setStyle("display", "inline-block");
	btnDelRow1.setStyle("display", "inline-block");
	if (!scwin.initData.isEqpChanged) {
		btnAddRow2.setStyle("display", "inline-block");
		btnDelRow2.setStyle("display", "inline-block");
		btnDownExcel2.setStyle("display", "inline-block");
		btnUploadExcel2.setStyle("display", "inline-block");
	}
	scwin.initData.isValidate = false;
};

/**
 * 설비현황 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow1_onclick = function() {
	var newIndex = dltWthtEqpSttusList.insertRow();

	grdWthtEqpSttusList.setFocusedCell(newIndex, "deptNm", true);
};

/**
 * 설비현황 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow1_onclick = function() {
	var rowIndexsList = grdWthtEqpSttusList.getAllFocusedRowIndex();

	dltWthtEqpSttusList.removeRows(rowIndexsList);
};
/**
 * 수익현황 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow2_onclick = function() {
	var newIndex = dltWthtExcclcSttusList.insertRow();
	var excclcRowJSON = dltWthtExcclcSttusList.getRowJSON(newIndex);

	var sttusRowJSON = grdWthtEqpSttusList.getRowJSON(grdWthtEqpSttusList.getFocusedRowIndex());
	excclcRowJSON.wthtSuplyBeginDe = sttusRowJSON.wthtSuplyBeginDe;
	excclcRowJSON.eqpNm = sttusRowJSON.eqpNm;

	dltWthtExcclcSttusList.setRowJSON(newIndex, excclcRowJSON, true);

	grdWthtExcclcSttusList.setFocusedCell(newIndex, "registDe", true);
};

/**
 * 수익현황 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow2_onclick = function() {
	var rowIndexsList = grdWthtExcclcSttusList.getAllFocusedRowIndex();

	dltWthtExcclcSttusList.removeRows(rowIndexsList);
};

/**
 * 그리드뷰의 내용을 검증한다.
 * @param
 * @return
 */
scwin.btnValidate_onclick = function(confirmValue) {
	if (confirmValue == true || confirmValue == undefined) {
		if (scwin.initData.isEqpChanged) {
			if (dltWthtEqpSttusList.getModifiedData() == "") {
				// 처리할 데이터가 없습니다.
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
				return;
			}

			if (utilLib.validateGridView(grdWthtEqpSttusList, scwin.initData.valInfoEqp)) {
				var columnList = scwin.initData.valInfoEqp.filter(obj => obj.mandatory).flatMap(obj => obj.id.replace("deptNm", "ecsChrgDeptId").replace("iemDivCd", "iemDivNm"));
				if (ecsLib.gridViewPkDuplicationCheck(grdWthtEqpSttusList, dltWthtEqpSttusList, columnList)) {
					// 중복 데이터가 있습니다.
					return;
				}

				if (ecsLib.validateGridViewAcb(grdWthtEqpSttusList, dltAutoCondition3, scwin.initData.acbMappingCdObj, scwin.initData.acbMappingNmObj)) {
					// 해당하는 {컬럼명}이(가) 존재하지 않습니다.
					return;
				}
				if (ecsLib.validateGridViewAcb(grdWthtEqpSttusList, dltAutoCondition2, scwin.initData.acbMappingCdObjDiv, scwin.initData.acbMappingNmObjDiv)) {
					// 해당하는 {컬럼명}이(가) 존재하지 않습니다.
					return;
				}

				scwin.initData.isValidate = true;
				if (scwin.initData.isSaveProcess) {
					scwin.initData.isSaveProcess = false;
					scwin.btnSave_onclick();
				} else {
					// 데이터 검증이 완료되었습니다.
					comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
				}
			}
		} else if (scwin.initData.isExcclcChanged) {
			if (dltWthtExcclcSttusList.getModifiedData() == "") {
				// 처리할 데이터가 없습니다.
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
				return;
			}

			if (utilLib.validateGridView(grdWthtExcclcSttusList, scwin.initData.valInfoExcclc)) {
				var columnList = scwin.initData.valInfoExcclc.filter(obj => obj.mandatory).flatMap(obj => obj.id);
				if (ecsLib.gridViewPkDuplicationCheck(grdWthtExcclcSttusList, dltWthtExcclcSttusList, columnList)) {
					// 중복 데이터가 있습니다.
					return;
				}

				scwin.initData.isValidate = true;
				if (scwin.initData.isSaveProcess) {
					scwin.initData.isSaveProcess = false;
					scwin.btnSave_onclick();
				} else {
					// 데이터 검증이 완료되었습니다.
					comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
				}
			}
		} else {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}
	} else {
		scwin.initData.isSaveProcess = false;
	}
};

/**
 * 그리드뷰의 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	scwin.initData.isSaveProcess = false;
	if (scwin.initData.isEqpChanged) {
		// 설비현황 처리할 데이터가 없을 때
		if (dltWthtEqpSttusList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		// 설비현황 데이터를 처리 한다.
		if (scwin.initData.isValidate) {
			var addCount = 0;
			var modifyCount = 0;
			var delCount = 0;
			dltWthtEqpSttusList.getModifiedJSON().forEach(obj => {
				var rowStatus = obj.rowStatus;
				switch(rowStatus) {
					case "C":
						// 추가
						addCount++;
						break;
					case "U":
						// 수정
						modifyCount++;
						break;
					case "E":
						// 삭제
						delCount++;
						break;
					default:
						break;
				}
			});
			var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
			// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
			ecsLib.saveRsn($p, `${dltWthtEqpSttusList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
		} else {
			scwin.initData.isSaveProcess = true;
			// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
			comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
			return;
		}
	} else if (scwin.initData.isExcclcChanged) {
		// 수익현황 처리할 데이터가 없을 때
		if (dltWthtExcclcSttusList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		// 수익현황 데이터를 처리 한다.
		if (scwin.initData.isValidate) {
			var addCount = 0;
			var modifyCount = 0;
			var delCount = 0;
			dltWthtExcclcSttusList.getModifiedJSON().forEach(obj => {
				var rowStatus = obj.rowStatus;
				switch(rowStatus) {
					case "C":
						// 추가
						addCount++;
						break;
					case "U":
						// 수정
						modifyCount++;
						break;
					case "E":
						// 삭제
						delCount++;
						break;
					default:
						break;
				}
			});
			var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
			// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
			ecsLib.saveRsn($p, `${dltWthtExcclcSttusList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
		} else {
			scwin.initData.isSaveProcess = true;
			// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
			comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
			return;
		}
	} else {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	if (scwin.initData.isEqpChanged) {
		requestData.dltWthtEqpSttusList = dltWthtEqpSttusList.getModifiedJSON();

		var option = {
			action : "cl/wthtexcclc/process-wtht-eqp-sttus.do",
			reqData : requestData,
			success : "scwin.saveConfirmSuccessCallback",
			savedToken : true,
			isShowMeg : false
		};
	} else if (scwin.initData.isExcclcChanged) {
		requestData.dltWthtExcclcSttusList = dltWthtExcclcSttusList.getModifiedJSON();

		var option = {
			action : "cl/wthtexcclc/process-wtht-excclc-sttus.do",
			reqData : requestData,
			success : "scwin.saveConfirmSuccessCallback",
			savedToken : true,
			isShowMeg : false
		};
	}
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveConfirmSuccessCallback = function(resBody) {
	if (scwin.initData.isExcclcChanged) {
		scwin.initData.oldEqpSttusWthtSuplyBeginDe = dltWthtExcclcSttusList.getModifiedJSON()[0].wthtSuplyBeginDe;
		scwin.initData.oldEqpSttusEqpNm = dltWthtExcclcSttusList.getModifiedJSON()[0].eqpNm;
	}
	comLib.alert($p, resBody.message.code_name);

	scwin.btnInqire_onclick();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	scwin.btnInqire_onclick();
};

/**
 * 설비현황 데이터컬렉션의 추가/변경/삭제 시 이벤트
 * @param
 * @return
 */
scwin.dltWthtEqpSttusList_ondatachange = function(info) {
	scwin.initData.isEqpChanged = true;
	grdWthtExcclcSttusList.setReadOnly(true);
	scwin.clearWthtEqpSttus();
	scwin.initData.isValidate = false;
};

/**
 * 수익현황 데이터컬렉션의 추가/변경/삭제 시 이벤트
 * @param
 * @return
 */
scwin.dltWthtExcclcSttusList_ondatachange = function(info) {
	scwin.initData.isExcclcChanged = true;
	btnAddRow1.setStyle("display", "none");
	btnDelRow1.setStyle("display", "none");
	scwin.initData.isValidate = false;
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	dmaSearchParam.set("basinCd", info.newValue);
};

scwin.acbDiv_onviewchange = function(info) {
