/**
 * 수열 설비현황 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel1_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnWthtEqpLabel.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 10,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	// 데이터가 없어도 탬플릿만 다운받을 수 있게 comLib.downloadExcel 말고 grdID.advancedExcelDownload 적용_231113
	options = {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		useDataFormat: true,
		applyDataFormat : true,
		rowHeight : 40,
		useStyle: true,
		hidden: 1
	}
	grdWthtEqpSttusList.advancedExcelDownload(options, infoArr);
};

