/**
 * 수열 설비현황 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdWthtEqpSttusList_onfilereadend = function(value) {
	var dltData = dltWthtEqpSttusList.getAllJSON();
	var dltAuto2 = dltAutoCondition2.getAllJSON();
	var dltAuto3 = dltAutoCondition3.getAllJSON();
	// set JSON
	for (var idx = 0; idx < dltData.length; idx++) {
		var deptNm = (dltAuto3.find(obj => obj.cmmnCd == dltData[idx].deptNm) || 0).cmmnCd;
		var iemDivNm = (dltAuto2.find(obj => obj.cmmnCd == dltData[idx].iemDivCd) || 0).cmmnCd;
		dltWthtEqpSttusList.setCellData(idx, "deptNm", deptNm);
		dltWthtEqpSttusList.setCellData(idx, "iemDivNm", iemDivNm);
	}
};

