 * @return
 */
scwin.grdWthtExcclcSttusList_onfilereadend = function(value) {
	var dltData = dltWthtExcclcSttusList.getAllJSON();
	var wthtEqpSttusRowData = grdWthtEqpSttusList.getFocusedRowData();
	// set JSON
	for (var idx = 0; idx < dltData.length; idx++) {
		var wthtSuplyBeginDe = wthtEqpSttusRowData[3];
		var eqpNm = wthtEqpSttusRowData[4];
		dltWthtExcclcSttusList.setCellData(idx, "wthtSuplyBeginDe", wthtSuplyBeginDe);
		dltWthtExcclcSttusList.setCellData(idx, "eqpNm", eqpNm);
	}
};

/**
 * 공급가액, 부가세 수정시 수익금액을 계산한다.
 * @return
 */
scwin.grdWthtExcclcSttusList_onviewchange = function(info) {
	var row = info.rowIndex;
	var col = info.colIndex;
	var value = info.newValue;
	var colId = grdWthtExcclcSttusList.getColumnID(col);

	if (colId == "splval" || colId == "vat") {
		var data = dltWthtExcclcSttusList.getRowJSON(row);
		var splval = data.splval;
		var vat = data.vat;
		data.excclcAmt = Number(splval) + Number(vat);
		dltWthtExcclcSttusList.setRowJSON(row, data, true);
	}
};
